SELECT * FROM instruction

    
        AND status = #{status}
    
    
        AND instruction_type = #{instructionType}
    
    
        AND task_id = #{taskId}
    
    
        AND vehicle_id = #{vehicleId}
    
    
        AND create_time >= #{startTime}
    
    
        AND create_time <= #{endTime}
    

ORDER BY create_time DESC
LIMIT #{limit} OFFSET #{offset}
